<script setup>
import { computed, nextTick, onMounted, reactive, ref } from 'vue'
import AppIcon from '@/components/AppIcon.vue'
import {
  batchPublishArticles, createArticle, deleteArticle, deleteArticles, getArticle,
  getArticleOverview, getArticles, previewArticle, updateArticle, updateArticleStatus,
  uploadArticleFile,
} from '@/services/article'

const articles = ref([])
const overview = ref(null)
const loading = ref(true)
const selected = ref(new Set())
const openMenu = ref(null)
const busyIds = ref(new Set())
const message = ref(null)
const editor = ref(null)
const query = reactive({ keyword:'', status:'', sortOrder:'desc', page:1, size:10 })
const pager = reactive({ total:0, pages:1 })
const form = reactive({ open:false, mode:'create', loading:false, uploadingCover:false, uploadingAttachment:false, id:null, title:'', summary:'', content:'', coverUrl:null, attachmentUrl:null, attachmentName:null, attachmentSize:null, allowDownload:false, status:'DRAFT' })
const preview = reactive({ open:false, loading:false, data:null })
const confirmBox = reactive({ open:false, title:'', content:'', action:null, loading:false })

const allSelected = computed(() => articles.value.length > 0 && articles.value.every(item => selected.value.has(item.id)))
const pageNumbers = computed(() => {
  if (pager.pages <= 7) return Array.from({ length:pager.pages }, (_,i) => i + 1)
  return [...new Set([1,pager.pages,query.page-1,query.page,query.page+1])].filter(v => v > 0 && v <= pager.pages).sort((a,b) => a-b)
})
const metrics = computed(() => [
  { label:'文章总数', value:overview.value?.totalArticles, rate:overview.value?.monthOverMonth?.totalArticlesRate, icon:'▤', tone:'green' },
  { label:'已发布文章', value:overview.value?.publishedArticles, rate:overview.value?.monthOverMonth?.publishedArticlesRate, icon:'➤', tone:'lime' },
  { label:'草稿文章', value:overview.value?.draftArticles, rate:overview.value?.monthOverMonth?.draftArticlesRate, icon:'✎', tone:'orange' },
  { label:'本月浏览量', value:overview.value?.monthlyViews, rate:overview.value?.monthOverMonth?.monthlyViewsRate, icon:'◉', tone:'teal' },
])

function toast(text, type='success') { message.value={text,type}; window.setTimeout(() => { message.value=null },2600) }
function number(value) { return Number(value || 0).toLocaleString('zh-CN') }
function date(value) { if (!value) return '—'; const d=new Date(value); return Number.isNaN(d.getTime())?value:new Intl.DateTimeFormat('zh-CN',{year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit',hour12:false}).format(d).replaceAll('/','-') }
function statusLabel(status) { return { DRAFT:'草稿', PUBLISHED:'已发布', OFFLINE:'已下架' }[status] || status }

async function loadList() {
  loading.value=true
  try { const data=await getArticles(query); articles.value=data?.records||[]; pager.total=data?.total||0; pager.pages=data?.pages||1; if(query.page>pager.pages){query.page=pager.pages;return loadList()} }
  catch(error){toast(error.message,'error')} finally{loading.value=false}
}
async function loadOverview(){try{overview.value=await getArticleOverview()}catch(error){toast(error.message,'error')}}
async function refresh(){selected.value=new Set();openMenu.value=null;await Promise.all([loadList(),loadOverview()])}
function search(){query.page=1;selected.value=new Set();loadList()}
function reset(){Object.assign(query,{keyword:'',status:'',sortOrder:'desc',page:1});loadList()}
function goPage(page){if(page<1||page>pager.pages||page===query.page)return;query.page=page;selected.value=new Set();loadList()}
function toggleOne(id){const next=new Set(selected.value);next.has(id)?next.delete(id):next.add(id);selected.value=next}
function toggleAll(){selected.value=allSelected.value?new Set():new Set(articles.value.map(item=>item.id))}

function clearForm(){Object.assign(form,{loading:false,uploadingCover:false,uploadingAttachment:false,id:null,title:'',summary:'',content:'',coverUrl:null,attachmentUrl:null,attachmentName:null,attachmentSize:null,allowDownload:false,status:'DRAFT'})}
async function openCreate(){clearForm();form.mode='create';form.open=true;await nextTick();if(editor.value)editor.value.innerHTML=''}
async function openEdit(row){clearForm();form.mode='edit';form.open=true;form.loading=true;form.id=row.id;openMenu.value=null;try{const detail=await getArticle(row.id);Object.assign(form,detail,{summary:detail.summary||'',content:detail.content||'',allowDownload:Boolean(detail.allowDownload)});await nextTick();if(editor.value)editor.value.innerHTML=form.content}catch(error){form.open=false;toast(error.message,'error')}finally{form.loading=false}}
function syncContent(){form.content=editor.value?.innerHTML||''}
function format(command,value=null){editor.value?.focus();document.execCommand(command,false,value);syncContent()}
function plainText(html){const div=document.createElement('div');div.innerHTML=html;return (div.textContent||'').trim()}
async function save(targetStatus=null){
  if(form.loading)return
  syncContent();const title=form.title.trim();if(!title)return toast('请输入文章标题','error');if(title.length>200)return toast('文章标题不能超过 200 个字符','error');if(form.summary.length>500)return toast('摘要不能超过 500 个字符','error');if(!plainText(form.content))return toast('请输入文章正文','error');if(form.allowDownload&&!form.attachmentUrl)return toast('允许下载前请先上传附件','error')
  form.loading=true
  const payload={title,summary:form.summary.trim()||null,content:form.content,coverUrl:form.coverUrl||null,attachmentUrl:form.attachmentUrl||null,attachmentName:form.attachmentUrl?form.attachmentName:null,attachmentSize:form.attachmentUrl?form.attachmentSize:null,allowDownload:Boolean(form.allowDownload)}
  try{if(form.mode==='create')await createArticle({...payload,status:targetStatus||'DRAFT'});else await updateArticle(form.id,payload);form.open=false;toast(form.mode==='create'?(targetStatus==='PUBLISHED'?'文章已发布':'文章已保存为草稿'):'文章已更新');await refresh()}catch(error){toast(error.message,'error')}finally{form.loading=false}
}
async function upload(file,type){if(!file)return;if(type==='attachment'&&!/\.(pdf|doc|docx)$/i.test(file.name))return toast('附件仅支持 PDF、DOC、DOCX','error');const key=type==='cover'?'uploadingCover':'uploadingAttachment';form[key]=true;try{const result=await uploadArticleFile(file,type==='cover'?'articles/covers':'articles/attachments');if(type==='cover')form.coverUrl=result.url;else{form.attachmentUrl=result.url;form.attachmentName=result.name;form.attachmentSize=result.size}toast('文件上传成功')}catch(error){toast(error.message,'error')}finally{form[key]=false}}
function removeAttachment(){form.attachmentUrl=null;form.attachmentName=null;form.attachmentSize=null;form.allowDownload=false}

async function showPreview(row){preview.open=true;preview.loading=true;preview.data=null;openMenu.value=null;try{preview.data=await previewArticle(row.id)}catch(error){preview.open=false;toast(error.message,'error')}finally{preview.loading=false}}
async function changeStatus(row,status){openMenu.value=null;const next=new Set(busyIds.value);next.add(row.id);busyIds.value=next;try{await updateArticleStatus(row.id,status);toast(`文章已${statusLabel(status)}`);await refresh()}catch(error){toast(error.message,'error')}finally{const done=new Set(busyIds.value);done.delete(row.id);busyIds.value=done}}
function ask(title,content,action){Object.assign(confirmBox,{open:true,title,content,action,loading:false});openMenu.value=null}
async function confirmAction(){confirmBox.loading=true;try{await confirmBox.action?.();confirmBox.open=false}catch{}finally{confirmBox.loading=false}}
function removeOne(row){ask('删除文章',`确定删除“${row.title}”吗？文章将被软删除。`,async()=>{try{await deleteArticle(row.id);toast('文章已删除');await refresh()}catch(error){toast(error.message,'error');throw error}})}
function batchPublish(){const ids=[...selected.value];if(!ids.length)return toast('请先选择文章','error');ask('批量发布',`将发布选中的 ${ids.length} 篇文章；任一文章状态不合法时整批回滚。`,async()=>{try{const result=await batchPublishArticles(ids);toast(`已发布 ${result?.publishedCount??ids.length} 篇文章`);await refresh()}catch(error){toast(error.message,'error');throw error}})}
function batchDelete(){const ids=[...selected.value];if(!ids.length)return toast('请先选择文章','error');ask('批量删除',`确定删除选中的 ${ids.length} 篇文章吗？任一 ID 无效时整批回滚。`,async()=>{try{const result=await deleteArticles(ids);toast(`已删除 ${result?.deletedCount??ids.length} 篇文章`);await refresh()}catch(error){toast(error.message,'error');throw error}})}
function possibleStatuses(status){return status==='DRAFT'?['PUBLISHED']:status==='PUBLISHED'?['OFFLINE','DRAFT']:['PUBLISHED']}

onMounted(refresh)
</script>

<template>
  <section class="article-page" @click.self="openMenu=null">
    <div v-if="message" class="toast" :class="message.type">{{ message.text }}</div>
    <div class="layout">
      <main class="main-column">
        <div class="filter-card card">
          <div class="filter-top"><label class="keyword"><input v-model="query.keyword" maxlength="100" placeholder="搜索文章标题、摘要或上传者..." @keyup.enter="search"/><AppIcon name="search" :size="18"/></label><button class="batch-publish" :disabled="!selected.size" @click="batchPublish">↥ 批量发布</button><button class="upload-button" @click="openCreate">＋ 上传文章</button></div>
          <div class="filter-bottom"><label>状态<select v-model="query.status" @change="search"><option value="">全部状态</option><option value="DRAFT">草稿</option><option value="PUBLISHED">已发布</option><option value="OFFLINE">已下架</option></select></label><label>上传时间<select v-model="query.sortOrder" @change="search"><option value="desc">从新到旧</option><option value="asc">从旧到新</option></select></label><button class="search-button" @click="search">查询</button><button class="reset" @click="reset">重置</button><button class="batch-delete" :disabled="!selected.size" @click="batchDelete">批量删除</button></div>
        </div>

        <div class="table-card card"><div class="table-scroll"><table><thead><tr><th><input type="checkbox" :checked="allSelected" @change="toggleAll"/></th><th>标题</th><th>上传者</th><th>上传时间</th><th>发布时间</th><th>浏览量</th><th>状态</th><th>操作</th></tr></thead><tbody v-if="!loading&&articles.length"><tr v-for="row in articles" :key="row.id"><td><input type="checkbox" :checked="selected.has(row.id)" @change="toggleOne(row.id)"/></td><td><div class="title-cell"><strong :title="row.title">{{ row.title }}</strong><span v-if="row.hasAttachment" title="包含附件">▱</span></div></td><td>{{ row.uploaderName||'未知用户' }}</td><td>{{ date(row.uploadedAt) }}</td><td>{{ date(row.publishedAt) }}</td><td>{{ number(row.viewCount) }}</td><td><span class="status" :class="row.status.toLowerCase()">{{ statusLabel(row.status) }}</span></td><td><div class="actions"><button title="预览" @click="showPreview(row)">◉</button><button title="编辑" @click="openEdit(row)">✎</button><div class="more"><button title="更多" @click.stop="openMenu=openMenu===row.id?null:row.id">•••</button><div v-if="openMenu===row.id" class="menu"><button v-for="status in possibleStatuses(row.status)" :key="status" @click="changeStatus(row,status)">{{ statusLabel(status) }}</button><button class="danger-text" @click="removeOne(row)">删除</button></div></div></div></td></tr></tbody></table><div v-if="loading" class="state"><span class="loader"></span>正在加载文章...</div><div v-else-if="!articles.length" class="state">暂无符合条件的文章</div></div>
          <footer><span>共 {{ number(pager.total) }} 条</span><nav><button :disabled="query.page===1" @click="goPage(query.page-1)">‹</button><template v-for="(page,index) in pageNumbers" :key="page"><i v-if="index&&page-pageNumbers[index-1]>1">…</i><button :class="{active:page===query.page}" @click="goPage(page)">{{ page }}</button></template><button :disabled="query.page===pager.pages" @click="goPage(query.page+1)">›</button></nav><select v-model="query.size" @change="query.page=1;loadList()"><option :value="10">10条/页</option><option :value="20">20条/页</option><option :value="50">50条/页</option></select></footer>
        </div>
      </main>
      <aside class="overview card"><h3>文章概览</h3><div class="metric" v-for="item in metrics" :key="item.label"><i :class="item.tone">{{ item.icon }}</i><div><span>{{ item.label }}</span><strong>{{ number(item.value) }}</strong><small v-if="item.rate!==null&&item.rate!==undefined" :class="{down:item.rate<0}">较上月 {{ item.rate>=0?'↑':'↓' }} {{ Math.abs(item.rate) }}%</small></div></div></aside>
    </div>

    <div v-if="form.open" class="overlay"><form class="editor-dialog dialog" @submit.prevent="save()"><header><h2>{{ form.mode==='create'?'上传文章':'编辑文章' }}</h2><button type="button" @click="form.open=false">×</button></header><div class="editor-body"><label>文章标题 <em>*</em><input v-model="form.title" maxlength="200" placeholder="请输入文章标题"/></label><label>文章摘要<textarea v-model="form.summary" maxlength="500" placeholder="请输入文章摘要（选填）"></textarea><small>{{ form.summary.length }}/500</small></label><label>正文内容 <em>*</em></label><div class="toolbar"><button type="button" @click="format('bold')"><b>B</b></button><button type="button" @click="format('italic')"><i>I</i></button><button type="button" @click="format('underline')"><u>U</u></button><button type="button" @click="format('formatBlock','h2')">H2</button><button type="button" @click="format('insertUnorderedList')">• 列表</button><button type="button" @click="format('removeFormat')">清除格式</button></div><div ref="editor" class="rich-editor" contenteditable="true" data-placeholder="请输入文章正文..." @input="syncContent"></div><div class="files"><label class="file-box"><span>封面图片</span><input type="file" accept="image/*" @change="upload($event.target.files[0],'cover')"/><b>{{ form.uploadingCover?'上传中...':form.coverUrl?'已上传，点击替换':'选择图片' }}</b><img v-if="form.coverUrl" :src="form.coverUrl" alt="封面预览"/></label><label class="file-box"><span>文章附件</span><input type="file" accept=".pdf,.doc,.docx,application/pdf,application/msword,application/vnd.openxmlformats-officedocument.wordprocessingml.document" @change="upload($event.target.files[0],'attachment')"/><b>{{ form.uploadingAttachment?'上传中...':form.attachmentName||'选择 PDF、DOC、DOCX' }}</b><button v-if="form.attachmentUrl" type="button" @click.prevent="removeAttachment">移除</button></label></div><label class="download"><input v-model="form.allowDownload" type="checkbox" :disabled="!form.attachmentUrl"/>允许用户下载附件</label></div><footer><button type="button" class="cancel" @click="form.open=false">取消</button><button v-if="form.mode==='create'" type="button" class="draft" :disabled="form.loading||form.uploadingCover||form.uploadingAttachment" @click="save('DRAFT')">保存草稿</button><button class="save" :disabled="form.loading||form.uploadingCover||form.uploadingAttachment" @click="form.mode==='create'&&save('PUBLISHED')">{{ form.loading?'保存中...':form.mode==='create'?'直接发布':'保存修改' }}</button></footer></form></div>

    <div v-if="preview.open" class="overlay" @mousedown.self="preview.open=false"><article class="preview-dialog dialog"><header><h2>文章预览</h2><button @click="preview.open=false">×</button></header><div v-if="preview.loading" class="state">正在加载预览...</div><div v-else-if="preview.data" class="preview-body"><img v-if="preview.data.coverUrl" :src="preview.data.coverUrl" alt="文章封面"/><span class="status" :class="preview.data.status.toLowerCase()">{{ statusLabel(preview.data.status) }}</span><h1>{{ preview.data.title }}</h1><p class="meta">上传者：{{ preview.data.uploaderName||'未知用户' }}</p><p v-if="preview.data.summary" class="summary">{{ preview.data.summary }}</p><div class="preview-content" v-html="preview.data.content"></div><p v-if="preview.data.attachmentName" class="attachment">附件：{{ preview.data.attachmentName }} · {{ preview.data.allowDownload?'允许下载':'禁止下载' }}</p></div></article></div>
    <div v-if="confirmBox.open" class="overlay"><div class="confirm-dialog dialog"><header><h2>{{ confirmBox.title }}</h2><button @click="confirmBox.open=false">×</button></header><div class="confirm-content"><i>!</i><p>{{ confirmBox.content }}</p></div><footer><button class="cancel" @click="confirmBox.open=false">取消</button><button class="danger" :disabled="confirmBox.loading" @click="confirmAction">{{ confirmBox.loading?'处理中...':'确定' }}</button></footer></div></div>
  </section>
</template>

<style scoped>
.article-page{min-height:calc(100vh - 79px);padding:20px;background:#f7f9f8;color:#29312d}.layout{display:grid;grid-template-columns:minmax(760px,1fr) 250px;gap:16px}.main-column{min-width:0;display:flex;flex-direction:column;gap:16px}.card{background:#fff;border:1px solid #e7ebe8;border-radius:14px;box-shadow:0 4px 14px rgba(17,62,42,.045)}.filter-card{padding:18px}.filter-top,.filter-bottom{display:flex;align-items:center;gap:12px}.filter-bottom{margin-top:14px;flex-wrap:wrap}.keyword{height:42px;display:flex;align-items:center;flex:1;padding:0 13px;border:1px solid #dce2de;border-radius:7px}.keyword input{flex:1;min-width:0;border:0;outline:0}.filter-card button{height:42px;padding:0 18px;border-radius:7px;cursor:pointer}.upload-button,.search-button{color:#fff;background:linear-gradient(90deg,#00683c,#087c46)}.batch-publish{color:#315f49;border:1px solid #cbd8d1;background:#fff}.batch-publish:disabled,.batch-delete:disabled{opacity:.45;cursor:not-allowed}.filter-bottom label{display:flex;align-items:center;gap:9px;font-size:13px}.filter-bottom select,.filter-bottom input{height:38px;padding:0 10px;border:1px solid #dce2de;border-radius:7px;background:#fff}.reset{color:#555;border:1px solid #ddd;background:#fff}.batch-delete{margin-left:auto;color:#d84545;border:1px solid #efcaca;background:#fff}.table-card{min-width:0;overflow:hidden}.table-scroll{overflow:auto}table{width:100%;min-width:1040px;border-collapse:collapse;font-size:13px}th{height:48px;background:#fbfcfb;text-align:left}td{height:54px;border-top:1px solid #edf0ee;color:#555d59}th:first-child,td:first-child{width:52px;padding-left:18px}th:nth-child(2){width:250px}th:nth-child(3){width:110px}th:nth-child(4),th:nth-child(5){width:170px}th:nth-child(6){width:90px}th:nth-child(7){width:100px}.title-cell{display:flex;align-items:center;gap:8px}.title-cell strong{max-width:220px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:#252b28;font-weight:500}.title-cell span{color:#158451}.status{di