f5a019}.metric span,.metric strong,.metric small{display:block}.metric span{color:#747b77;font-size:12px}.metric strong{margin:5px 0;font-size:23px}.metric small{color:#3b9b5d}.metric small.down{color:#dd5353}.toast{position:fixed;z-index:60;top:92px;left:50%;transform:translateX(-50%);padding:11px 20px;color:#fff;background:#238b57;border-radius:8px;box-shadow:0 8px 25px rgba(0,0,0,.15)}.toast.error{background:#ce4e4e}.overlay{position:fixed;z-index:40;inset:0;display:grid;place-items:center;padding:20px;background:rgba(11,31,21,.42);backdrop-filter:blur(2px)}.dialog{overflow:hidden;background:#fff;border-radius:14px;box-shadow:0 20px 60px rgba(0,35,20,.22)}.dialog>header{height:62px;display:flex;align-items:center;justify-content:space-between;padding:0 23px;border-bottom:1px solid #eaeeeb}.dialog h2{margin:0;font-size:19px}.dialog header button{font-size:25px;color:#727a76;background:none;cursor:pointer}.editor-dialog{width:min(860px,96vw);max-height:94vh}.editor-body{max-height:calc(94vh - 127px);padding:22px;overflow:auto}.editor-body>label{display:block;margin:0 0 9px;font-size:13px;font-weight:600}.editor-body>label>input,.editor-body textarea{width:100%;margin-top:8px;padding:10px 12px;border:1px solid #dce1de;border-radius:7px;outline:none}.editor-body textarea{height:66px;resize:vertical}.editor-body label small{float:right;color:#999;font-weight:400}.editor-body em{color:#dc4040;font-style:normal}.toolbar{display:flex;gap:5px;padding:7px;border:1px solid #dce1de;border-bottom:0;border-radius:7px 7px 0 0;background:#fafbfa}.toolbar button{height:30px;padding:0 10px;border:1px solid #e2e5e3;border-radius:4px;background:#fff;cursor:pointer}.rich-editor{min-height:190px;padding:14px;border:1px solid #dce1de;border-radius:0 0 7px 7px;outline:none;line-height:1.7}.rich-editor:empty:before{content:attr(data-placeholder);color:#aaa}.files{display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-top:18px}.file-box{position:relative;min-height:92px;padding:14px;b